func dfs(graph map[int][]int, start int) []int {
    visited := map[int]bool{}
    stack := []int{start}
    var order []int
    for len(stack) > 0 {
        node := stack[len(stack)-1]
        stack = stack[:len(stack)-1]
        if visited[node] { continue }
        visited[node] = true
        order = append(order, node)
        for _, nb := range graph[node] {
            stack = append(stack, nb)
        }
    }
    return order
